// Function to preprocess the string
void preprocessString(char *str) {
    int len = strlen(str);
    char *processed = (char *)malloc((len + 1) * sizeof(char));
    int j = 0;

    for (int i = 0; i < len; i++) {
        // Check if it's an alphanumeric character
        if (isalnum(str[i])) {
            // Convert to lowercase
            processed[j++] = tolower(str[i]);
        }
    }
    processed[j] = '\0'; // Null-terminate the processed string

    // Copy the processed string back to the original string
    strncpy(str, processed, len);
    free(processed);
}

// Function to check if a string is a palindrome
int isPalindrome(char *str) {
    int left = 0;
    int right = strlen(str) - 1;

    while (left < right) {
        if (str[left] != str[right]) {
            return 0; // Not a palindrome
        }
        left++;
        right--;
    }
    return 1; // Palindrome
}

