```php
<?php
function isPerfectSquare($number) {
    // Check if the input is a positive integer
    if (!is_int($number) || $number < 0) {
        return "Error: Input must be a non-negative integer.";
    }

    // Calculate the square root and round it
    $sqrt = sqrt($number);

    // Check if the rounded square root squared equals the original number
    if (round($sqrt) ** 2 == $number) {
        return "The number {$number} is a perfect square.";
    } else {
        return "The number {$number} is not a perfect square.";
    }
}

// Example usage:
$input = (int) readline("Enter a non-negative integer: ");
echo isPerfectSquare($input);
?>
```

